            CREATE OR REPLACE FUNCTION sync_module_crf_to_crf()
            RETURNS TRIGGER AS $$
            BEGIN
                IF (TG_OP = 'INSERT') THEN
                    INSERT INTO crf (
                        crf_id, name, description, oc_oid, status_id,
                        owner_id, source_study_id, date_created, date_updated, update_id
                    )
                    VALUES (
                        NEW.crf_id, NEW.name, NEW.description, NEW.oc_oid, NEW.status_id,
                        NEW.owner_id, NEW.source_study_id, NEW.date_created, NEW.date_updated, NEW.update_id
                    );
                    RETURN NEW;
                ELSIF (TG_OP = 'UPDATE') THEN
                    UPDATE crf SET
                        name = NEW.name,
                        description = NEW.description,
                        oc_oid = NEW.oc_oid,
                        status_id = NEW.status_id,
                        owner_id = NEW.owner_id,
                        source_study_id = NEW.source_study_id,
                        date_created = NEW.date_created,
                        date_updated = NEW.date_updated,
                        update_id = NEW.update_id
                    WHERE crf_id = OLD.crf_id;
                    RETURN NEW;
                ELSIF (TG_OP = 'DELETE') THEN
                    DELETE FROM crf WHERE crf_id = OLD.crf_id;
                    RETURN OLD;
                END IF;
            END;
            $$ LANGUAGE plpgsql;

            CREATE TRIGGER trg_sync_module_crf
            AFTER INSERT OR UPDATE OR DELETE ON module_crf
            FOR EACH ROW EXECUTE FUNCTION sync_module_crf_to_crf();
